import java.io.*;

public class CommandInjectionSecure {

    public static void main(String[] args) {
        try {
            // Simulating user input
            String userInput = "test.txt";

            // Validate and sanitize user input
            if (!userInput.matches("[a-zA-Z0-9._-]+")) {
                throw new IllegalArgumentException("Invalid input provided");
            }

            // Safe command execution by providing arguments separately
            ProcessBuilder processBuilder = new ProcessBuilder("cat", userInput);
            Process process = processBuilder.start();

            // Reading the output of the command
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException | IllegalArgumentException e) {
            e.printStackTrace();
        }
    }
}

